#include<bits/stdc++.h>
using namespace std;
int a[101],c[101];
bitset<100010> dp;
int main()
{
    int n,m;
    while(scanf("%d%d",&n,&m)==2&&n)
    {
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
        }
        dp.reset();
        dp[0]=1;
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&c[i]);
            for(int j=1;j<=c[i];j++)
            {
                dp|=(dp<<a[i]);
            }
        }
        int ans=0;
        for(int i=1;i<=m;i++)
        {
            ans+=dp[i];
        }
        printf("%d\n",ans);
    }
    return 0;
}
